use std::collections::VecDeque;

struct StateMachineIterator {
    data: VecDeque<i32>,
    index: usize,
}

impl Iterator for StateMachineIterator {
    type Item = i32;

    fn next(&mut self) -> Option<Self::Item> {
        if self.index >= self.data.len() {
            return None;
        }
        let item = self.data[self.index];
        self.index += 1;
        Some(item)
    }
}

fn main() {
    let raw_data = vec![10, 20, 30, 40, 50];
    let initial_queue: VecDeque<i32> = raw_data.into_iter().collect();

    let mut iterator = StateMachineIterator {
        data: initial_queue,
        index: 0,
    };

    let processed_items: Vec<i32> = iterator.by_ref().collect();

    println!("Processed items: {:?}", processed_items);
}

use std::collections::VecDeque;

struct StateTrackerIterator<T> {
    data: VecDeque<T>,
    state: i32,
    current_count: usize,
}

impl<T> Iterator for StateTrackerIterator<T> {
    type Item = (T, i32);

    fn next(&mut self) -> Option<Self::Item> {
        if let Some(item) = self.data.pop_front() {
            self.state += 1;
            let result = (item, self.state);
            Some(result)
        } else {
            None
        }
    }
}

fn main() {
    let raw_data: Vec<String> = vec!["KeyA".to_string(), "KeyB".to_string(), "KeyC".to_string(), "KeyD".to_string()];

    let mut deque: VecDeque<String> = raw_data.into_iter().collect();

    let mut iterator = StateTrackerIterator { 
        data: deque,
        state: 0,
        current_count: 0,
    };

    println!("Starting stateful iteration...");
    for (key, count) in iterator {
        println!("Processed key: \"{}\", and current state counter is: {}", key, count);
    }
}

use std::collections::VecDeque;

struct ParticleSystemIterator {
    data: VecDeque<f32>,
    current_time: f32,
}

impl Iterator for ParticleSystemIterator {
    type Item = (f32, VecDeque<f32>);

    fn next(&mut self) -> Option<Self::Item> {
        if self.data.is_empty() && self.current_time > 10.0 {
            return None;
        }

        let initial_state = self.data.clone();
        self.current_time += 0.1;

        let mut next_data = VecDeque::new();
        let num_particles = initial_state.len();

        for i in 0..num_particles {
            let current_pos = initial_state[i];
            let time_influence = self.current_time * 0.1;
            let new_x = current_pos + (i as f32) * 0.05 - time_influence;
            let new_y = (self.current_time / 2.0).sin() * 5.0 + initial_state[i] * 0.1;

            next_data.push_back(new_x);
            next_data.push_back(new_y);
        }

        if next_data.is_empty() {
            return None;
        }

        self.data = next_data.clone();
        Some((self.current_time, next_data))
    }
}

fn main() {
    let initial_positions: VecDeque<f32> = (0..10).map(|_| 5.0).collect();
    let mut iterator = ParticleSystemIterator {
        data: initial_positions,
        current_time: 0.0,
    };

    for result in iterator.by_ref().take(2) {
        println!("Time Step Processed: {:.1}", result.0);
        let end = std::cmp::min(3, result.1.len());
        if end > 0 {
            let sample_range = result.1.iter().take(end).collect::<Vec<_>>();
            println!("New State Sample (first {}): {:?}", end, sample_range);
        } else {
            println!("New State Sample (first 3): []");
        }
    }
}

use std::collections::VecDeque;

struct BatchProcessor { 
    buffer: VecDeque<i32>,
}

impl Default for BatchProcessor { 
    fn default() -> Self { 
        BatchProcessor { buffer: VecDeque::new() }
    }
}

impl Iterator for BatchProcessor { 
    type Item = String;

    fn next(&mut self) -> Option<Self::Item> {
        if self.buffer.len() < 5 {
            return None;
        }

        let batch_elements: Vec<i32> = self.buffer.iter().cloned().collect();
        self.buffer.clear();

        let sum: i32 = batch_elements.into_iter().sum();
        Some(format!("BatchSum_{}", sum))
    }
}

fn process_identifiers(identifiers: &[i32]) -> Vec<String> {
    let mut processor = BatchProcessor::default();
    for &id in identifiers { 
        processor.buffer.push_back(id);
    }
    processor.collect::<Vec<_>>().into_iter().collect()
}

fn main() {
    let inputs = vec![10, 20, 30, 40, 50, 60, 70, 80];
    let results = process_identifiers(&inputs);
    for result in results { 
        println!("{}", result);
    }
}

use std::collections::VecDeque;

struct StateTracker<T> {
    data: VecDeque<T>,
}

impl<T> StateTracker<T> {
    fn new(initial_items: Vec<T>) -> Self {
        StateTracker {
            data: initial_items.into(),
        }
    }
}

impl<T> Iterator for StateTracker<T> {
    type Item = T;

    fn next(&mut self) -> Option<Self::Item> {
        if let Some(item) = self.data.pop_front() {
            Some(item)
        } else {
            None
        }
    }
}

fn main() {
    let initial_items = vec![10, 20, 30, 40];
    let mut tracker = StateTracker::new(initial_items);

    let mut sum: i32 = 0;
    let mut count: i32 = 0;

    for item in tracker {
        sum += item;
        count += 1;
        println!("Processed value: {}, Current Sum: {}", item, sum);
    }

    println!("nFinal Result - Total Count: {}", count);
}
